import { Reducer } from 'redux';

import { RootAction } from 'store';
import { UserActionTypes, UserState } from './types';

const initialUserState: UserState = {};

export const userReducer: Reducer<UserState, RootAction> = (state = initialUserState, action) => {
  switch (action.type) {
    case UserActionTypes.FETCH_USER_DATA__SUCCESS:
      return state;

    default:
      return state;
  }
};
