import { Reducer } from 'redux';

import { RootAction } from 'store';
import { GlobalActionTypes, GlobalState } from './types';

const initialState: GlobalState = {};

export const globalReducer: Reducer<GlobalState, RootAction> = (state = initialState, action) => {
  switch (action.type) {
    case GlobalActionTypes.SET_UNEXPECTED_ERROR:
      return {
        ...state,
        unexpectedError: action.error,
      };

    default:
      return state;
  }
};
