import { RootAction, RootState } from 'store';
import { AxiosError } from 'axios';

type ActionType = RootAction['type'];

export const selectRequestStatus = (state: RootState, actionType: ActionType): boolean => {
  const [requestName] = actionType.split(':');

  return state.apiRequests.statuses[requestName] || false;
};

export const selectRequestError = (state: RootState, actionType: ActionType): AxiosError | null => {
  const [requestName] = actionType.split(':');

  return state.apiRequests.errors[requestName] || null;
};
