import { AxiosError } from 'axios';
import { ApiRequestsState } from './types';

type Statuses = ApiRequestsState['statuses'];
type Errors = ApiRequestsState['errors'];

export const markAsInProgress = (state: Statuses, name: string): Statuses => {
  return { ...state, [name]: true };
};

export const markAsCompleted = (state: Statuses, name: string): Statuses => {
  const { [name]: removed, ...everythingElse } = state;
  return everythingElse;
};

export const storeError = (state: Errors, name: string, error: AxiosError<any>): Errors => {
  return { ...state, [name]: error };
};

export const removeError = (state: Errors, name: string): Errors => {
  const { [name]: removed, ...everythingElse } = state;
  return everythingElse;
};
