import React from 'react';

import { Router } from 'router';
import { Header, LogoSpinner } from 'components';
import { UnexpectedErrorPage } from 'pages';

import { Props, State } from './ApplicationModule.types';

export class ApplicationModule extends React.Component<Props, State> {
  state: State = {};

  // Lifecycle methods

  static getDerivedStateFromError(): State {
    return { catchedError: null };
  }

  componentDidMount(): void {
    this.props.fetchUserData();
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error(error, errorInfo);
  }

  // RENDER

  render() {
    const { unexpectedError, loadingUser } = this.props;
    const { catchedError } = this.state;

    if (catchedError || unexpectedError) {
      return <UnexpectedErrorPage />;
    }

    if (loadingUser) {
      return <LogoSpinner />;
    }

    return (
      <React.Fragment>
        <Header />
        <Router />
      </React.Fragment>
    );
  }
}
